1	export type Cell = [x: number, y: number];
2	
3	const NEIGHBOR_OFFSETS: ReadonlyArray<Cell> = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [0, -1],           [0, 1],
6	  [1, -1],  [1, 0],  [1, 1],
7	];
8	
9	const keyOf = ([x, y]: Cell): string => `${x},${y}`;
10	
11	const isAliveNextGen = (isLive: boolean, neighborCount: number): boolean =>
12	  neighborCount === 3 || (isLive && neighborCount === 2);
13	
14	const neighborsOf = ([x, y]: Cell): Cell[] =>
15	  NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
16	
17	export const nextGeneration = (liveCells: Cell[]): Cell[] => {
18	  const liveKeys = new Set(liveCells.map(keyOf));
19	  const candidates = new Map<string, { cell: Cell; count: number }>();
20	
21	  for (const neighbor of liveCells.flatMap(neighborsOf)) {
22	    const key = keyOf(neighbor);
23	    const prior = candidates.get(key)?.count ?? 0;
24	    candidates.set(key, { cell: neighbor, count: prior + 1 });
25	  }
26	
27	  return [...candidates]
28	    .filter(([key, { count }]) => isAliveNextGen(liveKeys.has(key), count))
29	    .map(([, { cell }]) => cell);
30	};
