const neighborsOf = ([x, y]: Cell): Cell[] =>
  NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);

export const nextGeneration = (liveCells: Cell[]): Cell[] => {
  const liveKeys = new Set(liveCells.map(keyOf));
  const candidates = new Map<string, { cell: Cell; count: number }>();

  for (const neighbor of liveCells.flatMap(neighborsOf)) {
    const key = keyOf(neighbor);
    const prior = candidates.get(key)?.count ?? 0;
    candidates.set(key, { cell: neighbor, count: prior + 1 });
  }

  return [...candidates]
    .filter(([key, { count }]) => isAliveNextGen(liveKeys.has(key), count))
    .map(([, { cell }]) => cell);
};

